import assert from 'node:assert';

import {
  Verdict,
  isAccept,
  isDefer,
  isReject,
} from '@a0n/bitwise';

import { auditDarkShroudBundle, deriveDarkShroud } from '../lib';
import { verdictForAction } from '../dark-shroud';

const bundleA = deriveDarkShroud({
  generatedAt: '2026-04-18T23:10:00.000Z',
  source: 'test-suite',
  rejectionBudget: 5,
  routes: [
    {
      routeId: 'api-public',
      service: 'edge-api',
      localPort: 443,
      remotePortClass: 'internet',
      protocol: 'https',
      direction: 'ingress',
      trustTier: 'public',
      riskScore: 72,
      preserveConnectivity: true,
      evidenceMode: 'mirror',
    },
    {
      routeId: 'ops-admin',
      service: 'ops-console',
      localPort: 8443,
      remotePortClass: 'operator',
      protocol: 'https',
      direction: 'ingress',
      trustTier: 'control-plane',
      riskScore: 31,
      evidenceMode: 'snapshot',
    },
    {
      routeId: 'worker-egress',
      service: 'mesh-worker',
      localPort: 9000,
      remotePortClass: 'partner',
      protocol: 'tcp',
      direction: 'egress',
      trustTier: 'partner',
      riskScore: 18,
    },
  ],
});

const bundleB = deriveDarkShroud({
  generatedAt: '2026-04-18T23:10:00.000Z',
  source: 'test-suite',
  rejectionBudget: 5,
  routes: [
    {
      routeId: 'worker-egress',
      service: 'mesh-worker',
      localPort: 9000,
      remotePortClass: 'partner',
      protocol: 'tcp',
      direction: 'egress',
      trustTier: 'partner',
      riskScore: 18,
    },
    {
      routeId: 'ops-admin',
      service: 'ops-console',
      localPort: 8443,
      remotePortClass: 'operator',
      protocol: 'https',
      direction: 'ingress',
      trustTier: 'control-plane',
      riskScore: 31,
      evidenceMode: 'snapshot',
    },
    {
      routeId: 'api-public',
      service: 'edge-api',
      localPort: 443,
      remotePortClass: 'internet',
      protocol: 'https',
      direction: 'ingress',
      trustTier: 'public',
      riskScore: 72,
      preserveConnectivity: true,
      evidenceMode: 'mirror',
    },
  ],
});

assert.deepStrictEqual(bundleA, bundleB);
assert.strictEqual(bundleA.source, 'test-suite');
assert.strictEqual(bundleA.stateClassCount, 3);
assert.strictEqual(bundleA.weakestInspectionFloor, 1 / 18);
assert.deepStrictEqual(
  bundleA.decisions.map((decision) => [decision.routeId, decision.primaryAction]),
  [
    ['api-public', 'mirror'],
    ['ops-admin', 'mirror'],
    ['worker-egress', 'allow'],
  ]
);
assert.deepStrictEqual(bundleA.decisions[0]?.secondaryActions, ['rate_limit']);
assert.deepStrictEqual(bundleA.decisions[1]?.secondaryActions, ['snapshot']);
assert.strictEqual(bundleA.decisions[0]?.shroudMode, 'delayed-attested-route');
assert.strictEqual(bundleA.decisions[1]?.shroudMode, 'attested-route');
assert.strictEqual(bundleA.decisions[2]?.inspectionFloor, null);
assert.deepStrictEqual(bundleA.xRangerManifest.policy.actions, [
  'allow',
  'mirror',
  'rate_limit',
  'snapshot',
]);
assert.strictEqual(
  bundleA.xRangerManifest.policy.prismShroud.mode,
  'delayed-attested-route'
);

const audit = auditDarkShroudBundle(bundleA);
assert.strictEqual(audit.selfConsistent, true);
assert.deepStrictEqual(audit.issues, []);
assert.strictEqual(audit.boundaryAudit.selfConsistent, true);

const promoted = deriveDarkShroud({
  generatedAt: '2026-04-18T23:10:00.000Z',
  rejectionBudget: 2,
  routes: [
    {
      routeId: 'plain-a',
      service: 'plain',
      localPort: 8080,
      remotePortClass: 'internet',
      protocol: 'http',
      direction: 'ingress',
      trustTier: 'public',
      riskScore: 10,
    },
    {
      routeId: 'plain-b',
      service: 'plain',
      localPort: 8081,
      remotePortClass: 'internet',
      protocol: 'http',
      direction: 'ingress',
      trustTier: 'public',
      riskScore: 5,
    },
  ],
});

assert.strictEqual(promoted.weakestInspectionFloor, 1 / 6);
assert.strictEqual(promoted.decisions[0]?.primaryAction, 'mirror');
assert.strictEqual(
  promoted.decisions[0]?.reason,
  'baseline dark shroud promoted one route into mirrored observation'
);
assert.strictEqual(promoted.decisions[1]?.primaryAction, 'allow');

const drifted = auditDarkShroudBundle({
  ...bundleA,
  digest: `broken-${bundleA.digest}`,
});
assert.strictEqual(drifted.selfConsistent, false);
assert.ok(
  drifted.issues.includes(
    'digest does not match the canonical dark shroud body'
  )
);

// Canonical TritonVerdict adoption: the string `primaryAction` disposition is
// lossy; `verdict` recovers the signed-decision-with-neutral. The 'quarantine'
// string is the latent Abstain (the neutral middle), allow is Accept, and a hard
// drop/shroud is Decline.
//
// Direct mapping: 'quarantine' → Abstain, 'allow' → Accept, 'drop' → Decline.
assert.strictEqual(verdictForAction('quarantine'), Verdict.Abstain);
assert.ok(isDefer(verdictForAction('quarantine')));
assert.strictEqual(verdictForAction('allow'), Verdict.Accept);
assert.ok(isAccept(verdictForAction('allow')));
assert.strictEqual(verdictForAction('drop'), Verdict.Decline);
assert.ok(isReject(verdictForAction('drop')));
// Inspect-and-admit actions keep the route admissible under observation.
assert.strictEqual(verdictForAction('mirror'), Verdict.Accept);
assert.strictEqual(verdictForAction('rate_limit'), Verdict.Accept);
assert.strictEqual(verdictForAction('snapshot'), Verdict.Accept);

// End-to-end: the derived `verdict` rides additively on each decision next to the
// preserved string disposition.
const verdictBundle = deriveDarkShroud({
  generatedAt: '2026-04-18T23:10:00.000Z',
  source: 'verdict-suite',
  rejectionBudget: 5,
  routes: [
    {
      routeId: 'contained',
      service: 'hot',
      localPort: 6000,
      remotePortClass: 'internet',
      protocol: 'tcp',
      direction: 'ingress',
      trustTier: 'public',
      riskScore: 95, // >= 85, no preserveConnectivity → quarantine → Abstain
    },
    {
      routeId: 'open',
      service: 'cold',
      localPort: 7000,
      remotePortClass: 'partner',
      protocol: 'tcp',
      direction: 'egress',
      trustTier: 'partner',
      riskScore: 5, // low risk, no evidence → allow → Accept
    },
  ],
});

const contained = verdictBundle.decisions.find((d) => d.routeId === 'contained');
const open = verdictBundle.decisions.find((d) => d.routeId === 'open');
assert.ok(contained && open);
assert.strictEqual(contained?.primaryAction, 'quarantine');
assert.strictEqual(contained?.verdict, Verdict.Abstain);
assert.ok(isDefer(contained!.verdict));
assert.strictEqual(open?.primaryAction, 'allow');
assert.strictEqual(open?.verdict, Verdict.Accept);
assert.ok(isAccept(open!.verdict));

console.log('dark-shroud: all tests passed');
